import os
import sys
import subprocess

def install(packages):
    subprocess.check_call([sys.executable, "-m", "pip", "install", "--quiet"] + packages.split())

def apply_pyarrow_patch():
    try:
        import pyarrow
        class DummyExtensionType(pyarrow.ExtensionType):
            def __init__(self):
                super().__init__(pyarrow.null(), "arrow.py_extension_type")
            def __arrow_ext_serialize__(self):
                return b""
            @classmethod
            def __arrow_ext_deserialize__(cls, storage_type, serialized):
                return cls()
        pyarrow.register_extension_type(DummyExtensionType())
    except Exception:
        pass

