    import pandas as pd
    import numpy as np
    from scipy.stats import ttest_rel
    from sklearn.decomposition import PCA
    import pyarrow.parquet as pq

apply_pyarrow_patch()

def main():
    data_dir = '.'

    print("Loading trials...")
    try:
        trials = pq.read_table(os.path.join(data_dir, 'trials.parquet')).to_pandas()
    except Exception:
        trials = pd.read_parquet(os.path.join(data_dir, 'trials.parquet'))

    print("Loading units (this may take a moment)...")
    try:
        units = pq.read_table(
            os.path.join(data_dir, 'units.parquet'),
            columns=['subject_id', 'structure', 'spike_times', 'default_qc']
        ).to_pandas()
    except Exception:
        units = pd.read_parquet(
            os.path.join(data_dir, 'units.parquet'),
            columns=['subject_id', 'structure', 'spike_times', 'default_qc']
        )

    # Filter for good quality units
    units = units[units['default_qc'] == True]

    # Filter for frontal regions (ACA, PFC, PL, ILA, ORB)
    frontal_pattern = 'ACA|PL|ILA|ORB|PFC'
    units = units[units['structure'].str.contains(frontal_pattern, na=False)]
    print(f"Found {len(units)} high-quality frontal units across all subjects.\n")

    if len(units) == 0:
        print("No frontal units found. Cannot proceed with analysis.")
        return

    units_by_subject = dict(tuple(units.groupby('subject_id')))
    results = []

    for subject_id, subj_trials in trials.groupby('subject_id'):
        if subject_id not in units_by_subject:
            continue

        subj_units = units_by_subject[subject_id]
        unit_spike_times = subj_units['spike_times'].values

        # Precompute numpy arrays for fast searchsorted
        spikes_list = []
        for spikes in unit_spike_times:
            if spikes is not None:
                spikes_list.append(np.array(spikes))
            else:
                spikes_list.append(np.array([]))

        # Filter valid trials with a start time and ensure chronological order
        valid_trials = subj_trials.dropna(subset=['stim_start_time', 'block_index']).copy()
        valid_trials = valid_trials.sort_values('stim_start_time').reset_index(drop=True)

        # Process each block
        for block_idx, block_trials in valid_trials.groupby('block_index'):
            if len(block_trials) < 30:
                continue

            block_trials = block_trials.sort_values('stim_start_time')

            # Discovery phase: first 15 trials; Steady-state phase: last 15 trials
            first_15 = block_trials.iloc[:15]
            last_15 = block_trials.iloc[-15:]

            def get_pop_matrix(trials_subset):
                # Create a matrix of N_trials x N_units for the pre-stimulus window (-0.5s to 0s)
                pop_matrix = np.zeros((len(trials_subset), len(subj_units)))
                for j, spikes_arr in enumerate(spikes_list):
                    if len(spikes_arr) > 0:
                        for i, (_, trial) in enumerate(trials_subset.iterrows()):
                            t_start = trial['stim_start_time'] - 0.5
                            t_end = trial['stim_start_time']

                            idx_start = np.searchsorted(spikes_arr, t_start)
                            idx_end = np.searchsorted(spikes_arr, t_end)
                            pop_matrix[i, j] = (idx_end - idx_start) / 0.5
                return pop_matrix

            X_disc = get_pop_matrix(first_15)
            X_stead = get_pop_matrix(last_15)

            # Compute Participation Ratio to estimate effective dimensionality
            def compute_pr(X):
                if np.all(X == 0) or X.shape[1] == 0 or X.shape[0] < 2:
                    return np.nan
                pca = PCA()
                pca.fit(X)
                evals = pca.explained_variance_
                if np.sum(evals) == 0:
                    return np.nan
                pr = (np.sum(evals)**2) / np.sum(evals**2)
                return pr

            pr_disc = compute_pr(X_disc)
            pr_stead = compute_pr(X_stead)

            if not np.isnan(pr_disc) and not np.isnan(pr_stead):
                results.append({
                    'subject_id': subject_id,
                    'block_index': block_idx,
                    'pr_discovery': pr_disc,
                    'pr_steady': pr_stead
                })

    df_res = pd.DataFrame(results)

    if len(df_res) > 0:
        print(f"Analyzed {len(df_res)} blocks across {df_res['subject_id'].nunique()} subjects.")

        mean_pr_disc = df_res['pr_discovery'].mean()
        mean_pr_stead = df_res['pr_steady'].mean()

        print(f"Mean Dimensionality (PR) - Discovery phase: {mean_pr_disc:.4f}")
        print(f"Mean Dimensionality (PR) - Steady-state phase: {mean_pr_stead:.4f}")

        t_stat, p_val = ttest_rel(df_res['pr_discovery'], df_res['pr_steady'])
        print(f"Paired t-test: t = {t_stat:.4f}, p = {p_val:.4f}\n")

        if p_val < 0.05 and mean_pr_disc > mean_pr_stead:
            print("Conclusion: Significant decrease in dimensionality from discovery to steady-state phase, supporting Attractor Dynamics.")
        else:
            print("Conclusion: No significant decrease in dimensionality observed, which does not firmly support the specific Attractor Dynamics dimension collapse hypothesis tested.")
    else:
        print("No sufficient data found to perform the analysis.")

if __name__ == "__main__":
    main()
